import java.io.*;
import java.util.*;

public class XSSSecureCode {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter your name: ");
        String userInput = scanner.nextLine();

        // Sanitize user input to prevent XSS
        String safeUserInput = sanitizeUserInput(userInput);

        String welcomeMessage = "Welcome, " + safeUserInput + "!";

        System.out.println(welcomeMessage);
    }

    private static String sanitizeUserInput(String userInput) {
        // Replace special characters that can be used in XSS attacks with their HTML entity equivalents
        return userInput
            .replaceAll("&", "&amp;")
            .replaceAll("<", "&lt;")
            .replaceAll(">", "&gt;")
            .replaceAll("\"", "&quot;")
            .replaceAll("'", "&#39;");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
